 91→// Suggest learning (orchestrates gates then creates)
 92→// ---------------------------------------------------------------------------
 93→
 94→export async function suggestLearning(input: {
 95→  surreal: Surreal;
 96→  workspaceRecord: RecordId<"workspace", string>;
 97→  learning: CreateLearningInput;
 98→  embedding?: number[];
 99→  now: Date;
100→}): Promise<SuggestLearningResult> {
101→  const agentType = input.learning.suggestedBy ?? "unknown_agent";
102→
103→  // Gate 1: Rate limit
104→  const rateLimit = await checkRateLimit({
105→    surreal: input.surreal,
106→    workspaceRecord: input.workspaceRecord,
107→    agentType,
108→  });
109→
110→  if (rateLimit.blocked) {
111→    return { created: false, reason: "rate_limited", count: rateLimit.count };
112→  }
113→
114→  // Gate 2: Dismissed similarity (only when embedding available)
115→  if (input.embedding) {
116→    const dismissed = await checkDismissedSimilarity({
117→      surreal: input.surreal,
118→      workspaceRecord: input.workspaceRecord,
119→      proposedEmbedding: input.embedding,
120→    });
121→
122→    if (dismissed.blocked) {
123→      return {
124→        created: false,
125→        reason: "dismissed_similarity",
126→        matchedText: dismissed.matchedText,
127→      };
128→    }
129→  }
130→
131→  // Both gates passed -- create learning as pending_approval
132→  const learningRecord = await createLearning({
133→    surreal: input.surreal,
134→    workspaceRecord: input.workspaceRecord,
135→    learning: {
136→      ...input.learning,
137→      source: "agent",
138→    },
139→    now: input.now,
140→    embedding: input.embedding,
141→  });
142→
143→  return { created: true, learningRecord };
144→}
