 10→export async function createLearning(input: {
 11→  surreal: Surreal;
 12→  workspaceRecord: RecordId<"workspace", string>;
 13→  learning: CreateLearningInput;
 14→  now: Date;
 15→  embedding?: number[];
 16→}): Promise<LearningRecord> {
 17→  const learningRecord = new RecordId("learning", randomUUID());
 18→
 19→  const defaultStatus: LearningStatus = input.learning.source === "human" ? "active" : "pending_approval";
 20→  const status: LearningStatus = input.learning.forceStatus ?? defaultStatus;
 21→  const isActive = status === "active";
 22→
 23→  await input.surreal.create(learningRecord).content({
 24→    text: input.learning.text,
 25→    learning_type: input.learning.learningType,
 26→    status,
 27→    source: input.learning.source,
 28→    priority: input.learning.priority ?? "medium",
 29→    target_agents: input.learning.targetAgents ?? [],
 30→    workspace: input.workspaceRecord,
 31→    ...(input.learning.suggestedBy ? { suggested_by: input.learning.suggestedBy } : {}),
 32→    ...(input.learning.patternConfidence !== undefined ? { pattern_confidence: input.learning.patternConfidence } : {}),
 33→    ...(input.learning.createdBy ? { created_by: new RecordId("identity", input.learning.createdBy) } : {}),
 34→    ...(input.embedding ? { embedding: input.embedding } : {}),
 35→    ...(isActive ? { activated_at: input.now } : {}),
 36→    created_at: input.now,
 37→    updated_at: input.now,
 38→  });
 39→
 40→  // Create evidence edges
 41→  if (input.learning.evidenceIds && input.learning.evidenceIds.length > 0) {
 42→    for (const evidence of input.learning.evidenceIds) {
 43→      const evidenceRecord = new RecordId(evidence.table, evidence.id) as EvidenceTargetRecord;
 44→      await input.surreal
 45→        .relate(learningRecord, new RecordId("learning_evidence", randomUUID()), evidenceRecord, {
 46→          added_at: input.now,
 47→        })
 48→        .output("after");
 49→    }
 50→  }
 51→
 52→  return learningRecord;
 53→}
