const content = FILE_CONTENT;
// Find all mentions of 'learning' in the feed route
const learningLines = content
  .split('\n')
  .map((line, i) => ({ line, num: i + 1 }))
  .filter(({ line }) => line.toLowerCase().includes('learning'));

console.log('Feed route mentions of learning:');
learningLines.forEach(({ line, num }) => {
  console.log(`${num}: ${line.trim()}`);
});

// Check if learnings are created or just read
const createsLearning = content.includes('createLearning') || content.includes('suggestLearning');
console.log(`\nCreates learnings: ${createsLearning}`);

// Extract context around learning handling
const createIdx = content.indexOf('createLearning');
if (createIdx > -1) {
  const contextStart = Math.max(0, createIdx - 200);
  const contextEnd = Math.min(content.length, createIdx + 200);
  console.log('\nContext around createLearning:\n' + content.substring(contextStart, contextEnd));
}

